import{_ as a,o as r,c as n,a2 as s}from"./chunks/framework.Crpw6aS5.js";const t="/assets/01-vision-reference-demo.Da2eKbD4.png",i="/assets/02-cansub-interface.DDgKNYu1.png",o="/assets/03-obd2-db9-adapter.Bol26SjB.jpg",f=JSON.parse('{"title":"CAN Bus Reverse Engineering Skills (CSS Electronics)","description":"Imported notes on Claude Code skills for reverse-engineering CAN bus signals into DBC files using the CANsub interface.","frontmatter":{"title":"CAN Bus Reverse Engineering Skills (CSS Electronics)","description":"Imported notes on Claude Code skills for reverse-engineering CAN bus signals into DBC files using the CANsub interface."},"headers":[],"relativePath":"obd2/can-bus/github-css-electronics-can-bus-reverse-engineering-skills.md","filePath":"obd2/can-bus/github-css-electronics-can-bus-reverse-engineering-skills.md"}'),l={name:"obd2/can-bus/github-css-electronics-can-bus-reverse-engineering-skills.md"};function c(d,e,u,p,g,h){return r(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="can-bus-reverse-engineering-skills-css-electronics" tabindex="-1">CAN Bus Reverse Engineering Skills (CSS Electronics) <a class="header-anchor" href="#can-bus-reverse-engineering-skills-css-electronics" aria-label="Permalink to &quot;CAN Bus Reverse Engineering Skills (CSS Electronics)&quot;">​</a></h1><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li>Type: webpage</li><li>Origin: <a href="https://github.com/CSS-Electronics/can-bus-reverse-engineering-skills" target="_blank" rel="noreferrer">https://github.com/CSS-Electronics/can-bus-reverse-engineering-skills</a></li><li>Imported: 2026-06-29</li><li>Images: 3 saved under <code>./assets/github-css-electronics-can-bus-reverse-engineering-skills/</code></li></ul><h2 id="content" tabindex="-1">Content <a class="header-anchor" href="#content" aria-label="Permalink to &quot;Content&quot;">​</a></h2><p><a href="https://www.csselectronics.com" target="_blank" rel="noreferrer">CSS Electronics</a> publishes an open-source repo of <a href="https://www.claude.com/claude-code" target="_blank" rel="noreferrer">Claude Code</a> skills that help reverse engineer raw CAN bus data into decoding rules stored as DBC files. The workflow uses AI/LLM tools together with <a href="https://www.csselectronics.com/pages/python-can-usb-serial-api-stream" target="_blank" rel="noreferrer">python-can</a> scripts to identify which CAN ID and data bits encode a real-world value (speed, RPM, state of charge, and so on), derive start bit, length, endianness, scale, and offset, and verify the result.</p><p>The skills assume a <a href="https://www.csselectronics.com/products/can-fd-usb-interface-ethernet-cansub-2" target="_blank" rel="noreferrer">CANsub</a> CAN bus interface from CSS Electronics — either recording CSV log files via <a href="https://www.csselectronics.com/pages/webcan-can-bus-streaming-software-browser" target="_blank" rel="noreferrer">webCAN</a> or streaming data in real time over USB/Ethernet.</p><blockquote><p><strong>Note:</strong> This is an illustration of how CANsub + Python + AI can be used for CAN sniffing, not a polished production tool. See also the related article <a href="https://www.csselectronics.com/pages/can-bus-reverse-engineering-ai-llm-claude" target="_blank" rel="noreferrer">CAN bus reverse engineering with AI</a>.</p></blockquote><p><a href="https://cdn.shopify.com/videos/c/o/v/e384c5a75b7943e681dcbad2d10e230a.mp4" target="_blank" rel="noreferrer"><img src="'+t+'" alt="Watch the CAN bus reverse engineering demo"></a></p><h3 id="bundled-skills" tabindex="-1">Bundled skills <a class="header-anchor" href="#bundled-skills" aria-label="Permalink to &quot;Bundled skills&quot;">​</a></h3><p>Three skills auto-discover when you open the repo folder in Claude Code (under <code>.claude/skills/</code>):</p><table tabindex="0"><thead><tr><th>Skill</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>cansub-reverse-engineering</strong></td><td>End-to-end workflow: survey → correlate → bitsearch → build DBC → verify</td></tr><tr><td><strong>combine-dbc</strong></td><td>Merge per-signal DBCs into one application-level DBC</td></tr><tr><td><strong>cansub-knowledge</strong></td><td>CANsub specs and API reference (hardware, REST/WebSocket API, protocols, tools)</td></tr></tbody></table><h4 id="cansub-reverse-engineering" tabindex="-1">cansub-reverse-engineering <a class="header-anchor" href="#cansub-reverse-engineering" aria-label="Permalink to &quot;cansub-reverse-engineering&quot;">​</a></h4><p>Deterministic Python script chain replaces manual &quot;watch the screen for correlations.&quot; Supports three modes:</p><ol><li><strong>Offline</strong> — decode from an existing log (CAN + OBD2 CSV, MF4/CANedge, webCAN CSV) using a separately decodable reference (OBD2 PID, CANmod.gps, CANedge GPS/IMU on CAN9). No hardware required.</li><li><strong>Live</strong> — capture from a CANsub with a human-supplied reference value.</li><li><strong>Vision</strong> — user provides a CAN log plus a video of a dashboard/gauge display; local OCR digitizes the on-screen value as reference.</li></ol><p>Targets plain, non-multiplexed CAN signals. Scripts never transmit data frames; <code>capture.py</code> connects in normal mode by default so the CANsub ACKs received frames (required for single-node sensor-to-CAN modules).</p><h4 id="combine-dbc" tabindex="-1">combine-dbc <a class="header-anchor" href="#combine-dbc" aria-label="Permalink to &quot;combine-dbc&quot;">​</a></h4><p>Combines individual single-signal DBC files under <code>decoding-output/&lt;application&gt;/&lt;signal&gt;/&lt;signal&gt;.dbc</code> into <code>decoding-output/&lt;application&gt;/&lt;application&gt;.dbc</code>. Safe to re-run as new signals are confirmed.</p><h4 id="cansub-knowledge" tabindex="-1">cansub-knowledge <a class="header-anchor" href="#cansub-knowledge" aria-label="Permalink to &quot;cansub-knowledge&quot;">​</a></h4><p>Authoritative reference for CANsub.2 and CANsub.4: hardware specs, REST/WebSocket API, bit timing, filters, connectors, firmware, higher-layer protocols (OBD2, UDS, J1939, NMEA 2000, CANopen, CCP/XCP), and software tools (webCAN, SavvyCAN, PlotJuggler).</p><h3 id="recommended-hardware" tabindex="-1">Recommended hardware <a class="header-anchor" href="#recommended-hardware" aria-label="Permalink to &quot;Recommended hardware&quot;">​</a></h3><p><img src="'+i+'" alt="CANsub CAN bus interface streaming real-time in webCAN"></p><p><img src="'+o+`" alt="OBD2-DB9 adapter cable"></p><ul><li><a href="https://www.csselectronics.com/products/can-fd-usb-interface-ethernet-cansub-2" target="_blank" rel="noreferrer">CANsub.2</a> CAN FD interface with USB/Ethernet</li><li><a href="https://www.csselectronics.com/products/obd2-db9-adapter-cable" target="_blank" rel="noreferrer">OBD2-DB9 adapter cable</a> (optionally a <a href="https://www.csselectronics.com/products/contactless-can-bus-reader-adapter" target="_blank" rel="noreferrer">contactless adapter</a>)</li></ul><h3 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h3><ol><li><strong>Clone the repo</strong> (or download the ZIP).</li><li><strong>Install Python 3.10+</strong> — on Windows, tick &quot;Add python.exe to PATH&quot;.</li><li><strong>Install dependencies</strong> into a local <code>.venv</code>: <ul><li>Windows: run <code>install.bat</code></li><li>macOS / Linux: <code>python3 -m venv .venv &amp;&amp; .venv/bin/pip install -r requirements.txt</code></li></ul></li><li><strong>Claude Code</strong> — Claude Pro/Max subscription, VS Code, Claude Code extension, open the cloned folder so skills load automatically.</li><li><strong>Connect hardware</strong> — CANsub via USB, OBD2-DB9 cable to vehicle OBD2 port, engine or ignition on for live traffic. Verify streaming in webCAN first.</li></ol><h3 id="example-prompts" tabindex="-1">Example prompts <a class="header-anchor" href="#example-prompts" aria-label="Permalink to &quot;Example prompts&quot;">​</a></h3><ul><li>&quot;I&#39;ve connected my CANsub to my car via the OBD2-DB9 cable. Help me check if there is live proprietary CAN data available — and then help me reverse engineer my door locks.&quot;</li><li>&quot;Reverse engineer Speed and RPM from the proprietary CAN data found in Mercedes-E350-2010-obd2-can.csv (contains OBD2 reference data).&quot;</li><li>&quot;I have a CANedge log with proprietary vehicle CAN data plus the CANedge&#39;s internal GPS/IMU on CAN9. Use the GPS speed as the reference to reverse engineer the proprietary vehicle speed.&quot;</li><li>&quot;Help me reverse engineer Speed from my Opel Astra. I have put the raw CAN data in opel/ along with a video of the speed from my car&#39;s dashboard.&quot;</li><li>&quot;I have a gauge-to-CAN module with 8 gauges connected to my CANsub — help me reverse engineer the 1st gauge position signal.&quot;</li></ul><p>Sample data: <a href="https://www.csselectronics.com/pages/ai-can-bus-sniffer-data-pack" target="_blank" rel="noreferrer">CANsub CAN+OBD2 sample data pack</a>.</p><h3 id="output-structure" tabindex="-1">Output structure <a class="header-anchor" href="#output-structure" aria-label="Permalink to &quot;Output structure&quot;">​</a></h3><p>Each confirmed signal is saved under <code>decoding-output/</code>, grouped by application and signal:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>decoding-output/</span></span>
<span class="line"><span>  &lt;application&gt;/                         e.g. mercedes-e350/</span></span>
<span class="line"><span>    &lt;signal&gt;/&lt;signal&gt;.dbc                e.g. engine-rpm/engine-rpm.dbc</span></span>
<span class="line"><span>    &lt;signal&gt;/&lt;signal&gt;.png                verify plot (decoded vs reference)</span></span>
<span class="line"><span>    &lt;signal&gt;/analysis-plots/             survey / correlate / bit-search / fit plots</span></span>
<span class="line"><span>    &lt;application&gt;.dbc                     combined DBC across all signals</span></span></code></pre></div><p>Ask Claude to merge decoded signals:</p><blockquote><p>Combine the decoded DBCs for mercedes-e350 into a single DBC.</p></blockquote><p>Load the combined DBC in webCAN and stream live from CANsub for real-time confirmation.</p><h3 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h3><p>MIT License — free to use, modify, and distribute. Attribution appreciated: <a href="https://www.csselectronics.com/pages/can-bus-reverse-engineering-ai-llm-claude" target="_blank" rel="noreferrer">CAN bus reverse engineering with AI</a>.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Three Claude Code skills cover the full CAN reverse-engineering workflow: decode (<code>cansub-reverse-engineering</code>), merge (<code>combine-dbc</code>), and hardware reference (<code>cansub-knowledge</code>).</li><li>Works offline from existing logs (OBD2/GPS reference), live with CANsub, or via dashboard video + OCR for vision-based reference.</li><li>Output is per-signal DBC files under <code>decoding-output/</code>, combinable into an application-level DBC for live decoding in webCAN.</li><li>Requires CANsub hardware for live capture; sample CSV data is available for testing without a vehicle.</li></ul>`,38)])])}const m=a(l,[["render",c]]);export{f as __pageData,m as default};
